const Footer = () => {

return (
    <div className="grid g4 footer">
        <img width="100%" src="https://nexus.engin.umich.edu/wp-content/uploads/2021/08/CoE-horiz-rgb-1.svg" alt="Michigan Engineering, University of Michigan"></img>
        <div className="address">
            <h3>Nexus Main Office:</h3>
            <p>2401 Plymouth Road, Suite A/B<br/>Ann Arbor, MI 48105</p>
            <p><a href="tel:7346477200">(734) 647-7200</a></p>
            <p><a href="mailto:nexus-answers@umich.edu">nexus-answers@umich.edu</a></p>
        </div>
    </div>
)
}
export default Footer;
